#nullable enable // autogenerated

using System;
using System.Threading.Tasks;
using System.Xml;
using MVZ2.IO;
using MVZ2.TalkData;
using PVZEngine;

namespace MVZ2.Talk
{
    public static class TalkHelper
    {
        public static void SimpleStartTalk(this TalkController controller, NamespaceID groupId, int section, float delay = 0, Action? onSkipped = null, Action? onStarted = null, Action? onEnd = null)
        {
            if (controller.WillSkipTalk(groupId, section))
            {
                controller.AutoSkipTalks(groupId, section, () =>
                {
                    onSkipped?.Invoke();
                    onEnd?.Invoke();
                });
            }
            else
            {
                onStarted?.Invoke();
                controller.StartTalk(groupId, section, delay, onEnd: onEnd);
            }
        }
        public static async Task<TalkResult> SimpleStartTalkAsync(this TalkController controller, NamespaceID groupId, int section, float delay = 0, Action? onStarted = null)
        {
            if (controller.WillSkipTalk(groupId, section))
            {
                await controller.AutoSkipTalksAsync(groupId, section);
                return TalkResult.Skipped;
            }

            onStarted?.Invoke();
            await controller.StartTalkAsync(groupId, section, delay);
            return TalkResult.Started;
        }

        public static XmlNode? CreateTalkScriptNodes(this XmlDocument document, XmlNode node, string name, TalkScript[]? scripts, string? comment = null)
        {
            if (scripts != null && scripts.Length > 0)
            {
                document.AddComment(node, comment);

                var scriptsNode = document.CreateElement(name);
                foreach (var script in scripts)
                {
                    var scriptNode = document.CreateElement("script");
                    scriptNode.InnerText = script.ToString();
                    scriptsNode.AppendChild(scriptNode);
                }
                node.AppendChild(scriptsNode);
                return scriptsNode;
            }
            return null;
        }
    }
    public enum TalkResult
    {
        NotStarted,
        Skipped,
        Started
    }
}
